"""matplotlib.category — categorical axis support."""

import numpy as _np


class StrCategoryConverter:
    @staticmethod
    def convert(value, unit, axis):
        if isinstance(value, str):
            return 0.0
        return _np.asarray(value, dtype=float)

    @staticmethod
    def axisinfo(unit, axis):
        return None

    @staticmethod
    def default_units(data, axis):
        return None


class StrCategoryLocator:
    def __init__(self, units_mapping):
        self._units = units_mapping

    def __call__(self):
        return list(self._units.values())


class StrCategoryFormatter:
    def __init__(self, units_mapping):
        self._units = units_mapping

    def __call__(self, x, pos=None):
        for k, v in self._units.items():
            if v == x:
                return k
        return str(x)


class UnitData:
    def __init__(self, data=None):
        self._mapping = {}
        self._counter = 0
        if data is not None:
            self.update(data)

    def update(self, data):
        for d in data:
            s = str(d)
            if s not in self._mapping:
                self._mapping[s] = self._counter
                self._counter += 1

    def __len__(self):
        return len(self._mapping)
